get Owner(): UserData | null {
  return this.belongsTo&lt;UserData&gt;('Owner', 'OwnerId', User);
  //                                ^^^^^^^ Must match getter name!
}

// ❌ WRONG - Getter name doesn't match first parameter
get MyOwner(): UserData | null {
  return this.belongsTo&lt;UserData&gt;('Owner', 'OwnerId', User);
  //     ^^^^^^^^                  ^^^^^^^
  //     These must match!
}
</code></pre>

